code = '''
import os
import sys
import ast
import re
import json
import hashlib
import traceback
from datetime import datetime
from pathlib import Path
from collections import defaultdict

class CodeAnalyzer:
    """وكيل تحليل الاكواد المتقدم - يفحص كل ملف وسطر وحرف"""

    VERSION = "1.0.0"
    NAME = "CodeAnalyzer Agent"

    SKIP_DIRS = {
        ".venv", "venv", "env", "node_modules", "__pycache__",
        ".cache", ".git", "dist", "build", ".tox", ".eggs",
        "site-packages", ".mypy_cache", ".pytest_cache"
    }

    CODE_EXTENSIONS = {
        ".py": "Python", ".js": "JavaScript", ".ts": "TypeScript",
        ".jsx": "React JSX", ".tsx": "React TSX", ".java": "Java",
        ".c": "C", ".cpp": "C++", ".h": "C Header", ".cs": "C#",
        ".go": "Go", ".rs": "Rust", ".rb": "Ruby", ".php": "PHP",
        ".swift": "Swift", ".kt": "Kotlin", ".scala": "Scala",
        ".sh": "Shell", ".bash": "Bash", ".ps1": "PowerShell",
        ".bat": "Batch", ".cmd": "CMD"
    }

    CONFIG_EXTENSIONS = {
        ".json": "JSON", ".yaml": "YAML", ".yml": "YAML",
        ".toml": "TOML", ".ini": "INI", ".cfg": "Config",
        ".env": "Environment", ".xml": "XML", ".html": "HTML",
        ".css": "CSS"
    }

    def __init__(self, target_path, report_dir=None):
        self.target_path = Path(target_path).resolve()
        self.report_dir = Path(report_dir) if report_dir else self.target_path.parent / "CodeAnalyzer" / "reports"
        self.report_dir.mkdir(parents=True, exist_ok=True)
        self.findings = []
        self.file_stats = defaultdict(int)
        self.scan_summary = {}
        self.start_time = None
        self.errors_found = 0
        self.warnings_found = 0
        self.info_found = 0

    def scan(self):
        """تنفيذ الفحص الشامل"""
        self.start_time = datetime.now()
        print(f"[{self.NAME} v{self.VERSION}] بدء الفحص: {self.target_path}")
        print(f"الوقت: {self.start_time.strftime(chr(37)+\'Y-\'+ chr(37)+\'m-\'+chr(37)+\'d \'+chr(37)+\'H:\'+chr(37)+\'M:\'+chr(37)+\'S\')}")

        if self.target_path.is_file():
            self._analyze_file(self.target_path)
        elif self.target_path.is_dir():
            self._scan_directory(self.target_path)
        else:
            self._add_finding("ERROR", str(self.target_path), 0, "المسار غير موجود", "تحقق من صحة المسار المُعطى")

        end_time = datetime.now()
        duration = (end_time - self.start_time).total_seconds()

        self.scan_summary = {
            "target": str(self.target_path),
            "start_time": self.start_time.isoformat(),
            "end_time": end_time.isoformat(),
            "duration_seconds": round(duration, 2),
            "files_scanned": sum(self.file_stats.values()),
            "file_types": dict(self.file_stats),
            "total_findings": len(self.findings),
            "errors": self.errors_found,
            "warnings": self.warnings_found,
            "info": self.info_found
        }

        print(f"\nانتهى الفحص في {duration:.2f} ثانية")
        print(f"الملفات: {sum(self.file_stats.values())} | الأخطاء: {self.errors_found} | التحذيرات: {self.warnings_found} | معلومات: {self.info_found}")
        return self.scan_summary

    def _scan_directory(self, dir_path):
        """فحص مجلد بالكامل مع استثناء المجلدات غير المفيدة"""
        try:
            for entry in sorted(dir_path.iterdir()):
                if entry.is_dir():
                    if entry.name in self.SKIP_DIRS:
                        continue
                    self._scan_directory(entry)
                elif entry.is_file():
                    self._analyze_file(entry)
        except PermissionError:
            self._add_finding("WARNING", str(dir_path), 0, f"لا يمكن الوصول للمجلد: {dir_path}", "تحقق من صلاحيات الوصول")

    def _analyze_file(self, file_path):
        """تحليل ملف واحد بالكامل"""
        ext = file_path.suffix.lower()
        lang = self.CODE_EXTENSIONS.get(ext) or self.CONFIG_EXTENSIONS.get(ext)
        if not lang:
            return

        self.file_stats[lang] = self.file_stats.get(lang, 0) + 1
        rel_path = str(file_path)

        try:
            content = file_path.read_text(encoding="utf-8", errors="replace")
        except Exception as e:
            self._add_finding("ERROR", rel_path, 0, f"فشل قراءة الملف: {e}", "تحقق من ترميز الملف والصلاحيات")
            return

        lines = content.split("\n")

        # فحوصات عامة لجميع الملفات
        self._check_encoding_issues(rel_path, content, lines)
        self._check_large_file(rel_path, lines)
        self._check_trailing_whitespace(rel_path, lines)
        self._check_mixed_line_endings(rel_path, content)
        self._check_todo_fixme(rel_path, lines)

        # فحوصات خاصة بالبايثون
        if ext == ".py":
            self._analyze_python(rel_path, content, lines)

        # فحوصات خاصة بالجافاسكريبت/تايب سكريبت
        elif ext in (".js", ".ts", ".jsx", ".tsx"):
            self._analyze_javascript(rel_path, content, lines)

        # فحوصات ملفات الإعدادات
        if ext == ".json":
            self._analyze_json(rel_path, content)
        elif ext in (".yaml", ".yml"):
            self._analyze_yaml(rel_path, content)
        elif ext == ".env":
            self._analyze_env(rel_path, content, lines)

    def _analyze_python(self, filepath, content, lines):
        """تحليل ملف بايثون بالتفصيل"""
        # فحص الصيغة
        try:
            tree = ast.parse(content)
        except SyntaxError as e:
            self._add_finding("ERROR", filepath, e.lineno or 0, f"خطأ في الصيغة: {e.msg}", f"أصلح الصيغة في السطر {e.lineno}: {e.text}")
            return

        # فحص الاستيرادات
        imports = []
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    imports.append((alias.name, node.lineno))
            elif isinstance(node, ast.ImportFrom):
                if node.module:
                    imports.append((node.module, node.lineno))

        # كشف الاستيرادات المكررة
        seen_imports = {}
        for mod, line in imports:
            if mod in seen_imports:
                self._add_finding("WARNING", filepath, line, f"استيراد مكرر: {mod} (موجود أيضاً في سطر {seen_imports[mod]})", "أزل الاستيراد المكرر")
            seen_imports[mod] = line

        # كشف الدوال الطويلة جداً
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                func_lines = node.end_lineno - node.lineno + 1 if hasattr(node, "end_lineno") and node.end_lineno else 0
                if func_lines > 50:
                    self._add_finding("WARNING", filepath, node.lineno, f"دالة طويلة جداً: {node.name}() ({func_lines} سطر)", "قسّم الدالة إلى دوال أصغر لسهولة الصيانة")

                # كشف الدوال بدون docstring
                if not (node.body and isinstance(node.body[0], ast.Expr) and isinstance(node.body[0].value, (ast.Str, ast.Constant))):
                    self._add_finding("INFO", filepath, node.lineno, f"دالة بدون توثيق: {node.name}()", "أضف docstring لتوثيق الدالة")

        # كشف except عام (bare except)
        for node in ast.walk(tree):
            if isinstance(node, ast.ExceptHandler) and node.type is None:
                self._add_finding("WARNING", filepath, node.lineno, "except عام بدون تحديد نوع الخطأ", "حدد نوع الاستثناء مثل: except ValueError as e:")

        # فحص الأسطر لأنماط مشبوهة
        for i, line in enumerate(lines, 1):
            stripped = line.strip()
            if "eval(" in stripped and not stripped.startswith("#"):
                self._add_finding("ERROR", filepath, i, "استخدام eval() خطير أمنياً", "استبدل eval() بـ ast.literal_eval() أو بديل آمن")
            if "exec(" in stripped and not stripped.startswith("#"):
                self._add_finding("WARNING", filepath, i, "استخدام exec() قد يكون خطيراً", "تجنب exec() واستخدم بدائل أكثر أماناً")
            if re.search(r"password\s*=\s*[\'\"][^\'\"]+[\'\"]" , stripped, re.IGNORECASE):
                self._add_finding("ERROR", filepath, i, "كلمة مرور مكتوبة مباشرة في الكود", "استخدم متغيرات بيئية أو ملف .env")
            if re.search(r"(api_key|secret|token)\s*=\s*[\'\"][^\'\"]{8,}[\'\"]" , stripped, re.IGNORECASE):
                self._add_finding("ERROR", filepath, i, "مفتاح/رمز سري مكتوب مباشرة في الكود", "استخدم متغيرات بيئية أو ملف .env")
            if len(line) > 200:
                self._add_finding("INFO", filepath, i, f"سطر طويل جداً ({len(line)} حرف)", "قسّم السطر لعدة أسطر لسهولة القراءة")

    def _analyze_javascript(self, filepath, content, lines):
        """تحليل ملف جافاسكريبت/تايب سكريبت"""
        for i, line in enumerate(lines, 1):
            stripped = line.strip()
            if "var " in stripped and not stripped.startswith("//"):
                self._add_finding("WARNING", filepath, i, "استخدام var بدلاً من let/const", "استبدل var بـ let أو const")
            if "eval(" in stripped and not stripped.startswith("//"):
                self._add_finding("ERROR", filepath, i, "استخدام eval() خطير أمنياً", "استخدم بدائل آمنة مثل JSON.parse()")
            if "console.log" in stripped and not stripped.startswith("//"):
                self._add_finding("INFO", filepath, i, "console.log موجود (قد يكون للتطوير فقط)", "أزل أو استبدل بنظام logging مناسب للإنتاج")
            if "==" in stripped and "===" not in stripped and "!==" not in stripped and not stripped.startswith("//"):
                if re.search(r"[^!=<>]==[^=]", stripped):
                    self._add_finding("WARNING", filepath, i, "استخدام == بدلاً من === (مقارنة غير صارمة)", "استبدل == بـ === لمقارنة صارمة")

    def _analyze_json(self, filepath, content):
        """تحليل ملف JSON"""
        try:
            json.loads(content)
        except json.JSONDecodeError as e:
            self._add_finding("ERROR", filepath, e.lineno, f"خطأ في صيغة JSON: {e.msg}", f"أصلح الصيغة في السطر {e.lineno}، العمود {e.colno}")

    def _analyze_yaml(self, filepath, content):
        """تحليل ملف YAML"""
        try:
            import yaml
            yaml.safe_load(content)
        except ImportError:
            self._add_finding("INFO", filepath, 0, "مكتبة PyYAML غير مثبتة", "ثبّت: pip install pyyaml")
        except Exception as e:
            self._add_finding("ERROR", filepath, 0, f"خطأ في صيغة YAML: {e}", "تحقق من صيغة الملف")

    def _analyze_env(self, filepath, content, lines):
        """تحليل ملف .env"""
        for i, line in enumerate(lines, 1):
            stripped = line.strip()
            if not stripped or stripped.startswith("#"):
                continue
            if "=" not in stripped:
                self._add_finding("WARNING", filepath, i, f"سطر غير صالح في .env: {stripped[:50]}", "كل سطر يجب أن يكون بصيغة KEY=VALUE")
                continue
            key, _, value = stripped.partition("=")
            if not key.strip():
                self._add_finding("WARNING", filepath, i, "مفتاح فارغ في .env", "أضف اسم المتغير قبل =")
            if not value.strip():
                self._add_finding("INFO", filepath, i, f"قيمة فارغة للمتغير: {key.strip()}", "تأكد أن هذا مقصود")

    def _check_encoding_issues(self, filepath, content, lines):
        if "\ufffd" in content:
            self._add_finding("WARNING", filepath, 0, "الملف يحتوي على أحرف غير قابلة للقراءة (ترميز خاطئ)", "تحقق من ترميز الملف (UTF-8 موصى به)")

    def _check_large_file(self, filepath, lines):
        if len(lines) > 1000:
            self._add_finding("WARNING", filepath, 0, f"ملف كبير جداً ({len(lines)} سطر)", "فكّر في تقسيم الملف لوحدات أصغر")

    def _check_trailing_whitespace(self, filepath, lines):
        count = sum(1 for l in lines if l != l.rstrip())
        if count > 10:
            self._add_finding("INFO", filepath, 0, f"مسافات بيضاء زائدة في {count} سطر", "نظّف المسافات الزائدة")

    def _check_mixed_line_endings(self, filepath, content):
        has_crlf = "\r\n" in content
        has_lf = "\n" in content.replace("\r\n", "")
        if has_crlf and has_lf:
            self._add_finding("WARNING", filepath, 0, "نهايات أسطر مختلطة (CRLF + LF)", "وحّد نهايات الأسطر")

    def _check_todo_fixme(self, filepath, lines):
        for i, line in enumerate(lines, 1):
            for tag in ["TODO", "FIXME", "HACK", "BUG", "XXX"]:
                if tag in line.upper():
                    self._add_finding("INFO", filepath, i, f"علامة {tag} موجودة: {line.strip()[:80]}", "تابع هذه الملاحظة")
                    break

    def _add_finding(self, severity, filepath, line, message, suggestion):
        finding = {
            "severity": severity,
            "file": filepath,
            "line": line,
            "message": message,
            "suggestion": suggestion,
            "timestamp": datetime.now().isoformat()
        }
        self.findings.append(finding)
        if severity == "ERROR":
            self.errors_found += 1
        elif severity == "WARNING":
            self.warnings_found += 1
        else:
            self.info_found += 1
        icon = {"ERROR": "❌", "WARNING": "⚠️", "INFO": "ℹ️"}.get(severity, "")
        print(f"  {icon} [{severity}] {filepath}:{line} — {message}")

    def get_findings_json(self):
        return json.dumps({"summary": self.scan_summary, "findings": self.findings}, ensure_ascii=False, indent=2)

    def save_report(self, fmt="json"):
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        if fmt == "json":
            path = self.report_dir / f"analysis_{ts}.json"
            path.write_text(self.get_findings_json(), encoding="utf-8")
        print(f"تم حفظ التقرير: {path}")
        return str(path)


